spec.expr:
max by (repository, hostname, frequency, repository_root) (
    (time() - cyborg_borg_prune_backup_oldest_timestamp_seconds{hostname=~"$hostname", repository=~"$repository"})
)

max by (repository, hostname, frequency) (
  (
    time() - cyborg_borg_backup_latest_timestamp_seconds{
      hostname=~"$hostname",
      repository=~"$repository",
      frequency="daily"
    }
  ) <= bool 24 * 3600
or
  (
    time() - cyborg_borg_backup_latest_timestamp_seconds{
      hostname=~"$hostname",
      repository=~"$repository",
      frequency="weekly"
    }
  ) <= bool 7 * 24 * 3600
)

max by (repository, hostname, frequency, compression) (
    cyborg_borg_backup_latest_timestamp_seconds{hostname=~"$hostname", repository=~"$repository"} * 1000
)

max by (repository, hostname) (
  (cyborg_borg_create_last_duration_seconds{hostname=~"$hostname", repository=~"$repository"})
) + max by (repository, hostname) (
  (cyborg_borg_prune_last_duration_seconds{hostname=~"$hostname", repository=~"$repository"})
) + max by (repository, hostname) (
  (cyborg_borg_compact_last_duration_seconds{hostname=~"$hostname", repository=~"$repository"})
)
